private boolean isPrototypePropertyAssign(Node assign) {
  Node n = assign.getFirstChild();
  if (n != null && NodeUtil.isVarOrSimpleAssignLhs(n, assign)
      && n.getType() == Token.GETPROP
      ) {
    Node firstChild = n.getFirstChild();
    if (firstChild != null && firstChild.getType() == Token.GETPROP) {
      Node secondChild = firstChild.getNext();
      if (secondChild != null && secondChild.getType() == Token.STRING && secondChild.getString().equals("prototype")) {
        return true;
      }
    }
  }
  return false;
}

private boolean isPrototypePropertyAssign(Node assign) {
  Node n = assign.getFirstChild();
  if (n != null && NodeUtil.isVarOrSimpleAssignLhs(n, assign)
      && n.getType() == Token.GETPROP
      ) {
    // Traverse to the last property in the chain
    while (n.getType() == Token.GETPROP) {
      n = n.getLastChild();
    }
    // Check if the last property is 'prototype'
    if (n.getType() == Token.STRING && "prototype".equals(n.getString())) {
      return true;
    }
  }

  return false;
}
